from typing import List

def generate_parenthesis(n: int) -> List[str]:
    result: List[str] = []

    def backtrack(open_rem: int, close_rem: int, current: str) -> None:
        if open_rem == 0 and close_rem == 0:
            result.append(current)
            return
        if open_rem > 0:
            backtrack(open_rem - 1, close_rem, current + '(')
        if close_rem > open_rem:
            backtrack(open_rem, close_rem - 1, current + ')')

    backtrack(n, n, '')
    return result
